import{_ as a,c as o,o as r,ae as n}from"./chunks/framework.Bw7rlmih.js";const h=JSON.parse('{"title":"CP-004: Provenance and Run Records","description":"","frontmatter":{},"headers":[],"relativePath":"control-plane/atomic/CP-004-provenance-and-run-records.md","filePath":"control-plane/atomic/CP-004-provenance-and-run-records.md"}'),l={name:"control-plane/atomic/CP-004-provenance-and-run-records.md"};function c(i,e,t,d,s,u){return r(),o("div",null,e[0]||(e[0]=[n('<h1 id="cp-004-provenance-and-run-records" tabindex="-1">CP-004: Provenance and Run Records <a class="header-anchor" href="#cp-004-provenance-and-run-records" aria-label="Permalink to &quot;CP-004: Provenance and Run Records&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>Make every resolved value and run explainable.</p><h2 id="inputs-outputs" tabindex="-1">Inputs / Outputs <a class="header-anchor" href="#inputs-outputs" aria-label="Permalink to &quot;Inputs / Outputs&quot;">​</a></h2><ul><li>Input: bundle execution request.</li><li>Output: resolved config + provenance map + run record.</li></ul><h2 id="public-interfaces" tabindex="-1">Public Interfaces <a class="header-anchor" href="#public-interfaces" aria-label="Permalink to &quot;Public Interfaces&quot;">​</a></h2><ul><li><code>konfigo run --server ... --bundle ... --explain</code></li><li><code>GET /v1/runs/{runId}</code></li><li><code>GET /v1/runs/{runId}/provenance</code></li></ul><h2 id="data-contracts" tabindex="-1">Data Contracts <a class="header-anchor" href="#data-contracts" aria-label="Permalink to &quot;Data Contracts&quot;">​</a></h2><p>Per-value provenance fields:</p><ul><li><code>path</code></li><li><code>resolvedValueHash</code></li><li><code>sourceType</code> (<code>bundle_values|connector|override|default</code>)</li><li><code>sourceRef</code> (e.g. <code>values:...:v9</code>, <code>vault:kv/...#42</code>)</li><li><code>resolvedAt</code></li></ul><p>RunRecord fields:</p><ul><li><code>runId</code></li><li><code>scope</code></li><li><code>bundleRef</code></li><li><code>bundleDigest</code></li><li><code>actor</code></li><li><code>result</code></li><li><code>startedAt/completedAt</code></li></ul><h2 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h2><ul><li>Every output path has provenance entry unless intentionally omitted by policy.</li><li>Sensitive values are redacted; hashes are retained.</li></ul><h2 id="failure-modes" tabindex="-1">Failure Modes <a class="header-anchor" href="#failure-modes" aria-label="Permalink to &quot;Failure Modes&quot;">​</a></h2><ul><li><code>500 provenance_capture_failed</code></li><li><code>403 provenance_access_denied</code></li></ul><h2 id="acceptance-criteria" tabindex="-1">Acceptance Criteria <a class="header-anchor" href="#acceptance-criteria" aria-label="Permalink to &quot;Acceptance Criteria&quot;">​</a></h2><ol><li><code>--explain</code> returns deterministic provenance entries.</li><li>Run record always includes bundle digest and actor.</li><li>Redaction policy masks secret values but preserves source metadata.</li></ol><h2 id="out-of-scope" tabindex="-1">Out of Scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of Scope&quot;">​</a></h2><ul><li>Full GUI explain visualizations.</li></ul><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li>CP-000 object model.</li><li>CP-005 connectors.</li></ul>',22)]))}const v=a(l,[["render",c]]);export{h as __pageData,v as default};
